from apps.core.models import BaseModel
class Order(BaseModel): user = models.ForeignKey('users.User', on_delete=models.PROTECT) total = models.DecimalField(max_digits=10, decimal_places=2) status = models.CharField(max_length=20, default='pending')
def __str__(self): return f"Order {self.uid} by {self.user}"

class Order(models.Model):
    def apply_discount(self, percentage):
        self.total = self.total * (1 - percentage / 100)
        self.save()  # No validation

from django.db.models import Q, CheckConstraint, UniqueConstraint

class Order(BaseModel):
    quantity = models.PositiveIntegerField()
    discount = models.DecimalField(max_digits=5, decimal_places=2)

    class Meta:
        constraints = [
            CheckConstraint(
                check=Q(discount__gte=0) & Q(discount__lte=100),
                name='valid_discount_pct',
            ),
            UniqueConstraint(
                fields=['user', 'product'],
                condition=Q(deleted_at__isnull=True),
                name='unique_active_user_product',  # PostgreSQL only
            ),
        ]

class ArticleQuerySet(models.QuerySet):
    def published(self):
        return self.filter(status='published', published_at__isnull=False)

    def by_author(self, user):
        return self.filter(author=user)

    def with_stats(self):
        return self.annotate(
            comment_count=models.Count('comments'),
            avg_rating=models.Avg('ratings__score'),
        )

class ArticleManager(models.Manager):
    def get_queryset(self):
        return ArticleQuerySet(self.model, using=self._db)

    def create_draft(self, *, title: str, author, content: str = '') -> 'Article':
        return self.create(title=title, author=author, content=content, status='draft')

class Article(BaseModel):
    title   = models.CharField(max_length=200)
    author  = models.ForeignKey('users.User', on_delete=models.PROTECT, related_name='articles')
    status  = models.CharField(max_length=20, default='draft')

    # Correct: Manager.from_queryset(QS)() — trailing () is required
    objects = ArticleManager.from_queryset(ArticleQuerySet)()

# Chainable:
Article.objects.published().by_author(user).with_stats()
# Factory method:
Article.objects.create_draft(title='Draft', author=user)

class SoftDeleteQuerySet(models.QuerySet):
    def delete(self):
        return self.update(deleted_at=timezone.now())

    def hard_delete(self):
        return super().delete()

    def alive(self):
        return self.filter(deleted_at__isnull=True)

    def dead(self):
        return self.filter(deleted_at__isnull=False)

class SoftDeleteManager(models.Manager):
    def get_queryset(self):
        return SoftDeleteQuerySet(self.model, using=self._db).alive()

# N+1: one query per order
for order in Order.objects.all():
    print(order.user.email)

# Single JOIN query
for order in Order.objects.select_related('user'):
    print(order.user.email)
